starterCss:
/* Create a horizontal nav:
   - Remove list bullets
   - Display items inline
   - Style links: no underline, dark text, 12px horizontal padding
   - First item should be bold
   - Odd items get a light background */
.nav {
  list-style: none;
  padding: 0;
  margin: 0;
}

referenceSolutions:
.nav {
  list-style: none;
  padding: 0;
  margin: 0;
}
.nav-item {
  display: inline-block;
}
.nav-item a {
  text-decoration: none;
  color: rgb(51, 51, 51);
  padding: 8px 12px;
  display: inline-block;
}
.nav-item:first-child a {
  font-weight: 700;
}
.nav-item:nth-child(odd) {
  background-color: rgb(245, 245, 245);
}

.nav {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
}
.nav-item a {
  text-decoration: none;
  color: #333;
  padding: 8px 12px;
  display: block;
}
.nav-item:first-child a {
  font-weight: bold;
}
.nav-item:nth-child(odd) {
  background-color: whitesmoke;
}

